def history_warning():
    "Issue a warning (once) ifw e are running in IPYthon with output cache enabled"
    if "get_ipython" in globals() and (ipython := get_ipython()) and ipython.cache_size > 0: # type: ignore
        warnings.warn("IPYthon has its output cache enabled. See https://xl0.github.io/lovely-tensors/history.html")

# %% ../../nbs/03_utils.utils.ipynb #3f9eee06
def in_debugger():
    """Returns True if a debugger was used.

    Note: This funciton will keep returning True even after you exit the debugger."""
    return getattr(sys, "gettrace", None) and sys.gettrace() is not None

# %% ../../nbs/03_utils.utils.ipynb #29dc103a
def svg_miniplot(counts: np.ndarray, width=60, height=18):
    counts = np.asarray(counts)
    if counts.size == 0:
        return ""

    step = width / len(counts)
    bar_w = max(step - 1.5, 1)
    rects = []

    scale = max(abs(v) for v in counts) or 1
    baseline_y = height - 1
    baseline = f"<line x1='0' y1='{baseline_y:.2f}' x2='{width}' y2='{baseline_y:.2f}' stroke='#c5ced8' stroke-width='1' />"
    for i, v in enumerate(counts):
        if v == 0:
            continue
        h = abs(v) / scale * (height - 2)
        y = height - 1 - h
        fill = '#2f6fed'
        rects.append(f"<rect x='{i * step:.2f}' y='{y:.2f}' width='{bar_w:.2f}' height='{max(h, 1):.2f}' rx='0.8' fill='{fill}' />")

    return (
        f"<svg width='{width}' height='{height}' viewBox='0 0 {width} {height}' xmlns='http://www.w3.org/2000/svg'  style='background:transparent'>"
        + '\n  '.join(("", baseline,  *rects))
        + "\n</svg>"
    )

